var e=JSON.parse(`[{"id":"L2_1","type":"dialog","speaker":"KYLE_DELTA_NULL_NULL","text":{"KOREA":"예? 휴가 말씀이십니까?","JPN":"はい？　休暇ですか？","ENG":"Pardon? A vacation?","TWN":"咦？您是說休假嗎？"},"stage":{"bg":"OFFICE","slots":{"L":null,"C":{"char_id":"KYLE_DELTA_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L3_1","type":"dialog","speaker":"MARIA_DELTA_NULL_NULL","text":{"KOREA":"그래. 한동안 전술평가로 바쁘게 뛰어다녔으니 자네도 숨 돌릴 여유 정도는 있어야지.","JPN":"そうだ。しばらく戦術評価で忙しく飛び回ってたから、君も息抜きする時間は必要だろう。","ENG":"Yes. You've kept yourself busy with the tactical evaluations for a while. You deserve a break.","TWN":"對。我看你一直為了戰術評估忙得不可開交，是時候休息一下了。"},"stage":{"bg":"OFFICE","slots":{"L":null,"C":{"char_id":"MARIA_DELTA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L4_1","type":"dialog","speaker":"KYLE_DELTA_NULL_NULL","text":{"KOREA":"저는 괜찮습니다. 오히려 일을 할 때가 가장 편안합니다.","JPN":"僕は大丈夫です。むしろ仕事をしてる時が一番落ち着きますので。","ENG":"I’m perfectly fine, ma'am. In fact, I feel more rested when I'm working.","TWN":"我沒關係的，反而是工作的時候我最感到安心。"},"stage":{"bg":"OFFICE","slots":{"L":null,"C":{"char_id":"KYLE_DELTA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L5_1","type":"dialog","speaker":"MARIA_DELTA_NULL_NULL","text":{"KOREA":"회의 때도 많이 피곤해 보이더구나, 카일.","JPN":"会議の時もかなり疲れてそうに見えたが、カイル少佐。","ENG":"You seemed exhausted during the meeting, Kyle.","TWN":"但你開會的時候看起來很疲倦啊，凱爾。"},"stage":{"bg":"OFFICE","slots":{"L":null,"C":{"char_id":"MARIA_DELTA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L6_1","type":"dialog","speaker":"MARIA_DELTA_NULL_NULL","text":{"KOREA":"자네 의사는 존중하지만, 과로가 자네의 업무처리에 걸림돌이 되는 건 원치 않아.","JPN":"君の意志は尊重するが、過労が君の業務処理の足手まといになってほしくないんだ。","ENG":"As much as I appreciate your dedication, I wouldn't want fatigue to become an obstacle in your work.","TWN":"我尊重你的想法，但是我不希望過度勞累會妨礙你的工作。"},"stage":{"bg":"OFFICE","slots":{"L":null,"C":{"char_id":"MARIA_DELTA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L7_1","type":"dialog","speaker":"KYLE_DELTA_NULL_NULL","text":{"KOREA":"그건...... 컨디션을 제대로 조절하지 못한 제 불찰이군요.","JPN":"それは……体調管理が至らなかった僕の不手際ですね。","ENG":"Well, I... I suppose I have failed to closely monitor my physical well-being.","TWN":"是……沒有調整好狀態確實是我的失誤。"},"stage":{"bg":"OFFICE","slots":{"L":null,"C":{"char_id":"KYLE_DELTA_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L8_1","type":"dialog","speaker":"MARIA_DELTA_NULL_NULL","text":{"KOREA":"그래. 그러니 일주일만 쉬다 오게. 당분간 부대에는 아무 일 없을 테니 부담 갖지 말고.","JPN":"そうだ。だから一週間だけでいいから休んで来たまえ。\\nしばらくは部隊に何もないと思うから遠慮することはない。","ENG":"That's right. So why don't you take a week off? Don't worry about us. Things will be slow around here for a while.","TWN":"沒錯。所以你就休息一週吧。部隊短時間內沒什麼事，不要太有壓力，好好享受你的假期吧。"},"stage":{"bg":"OFFICE","slots":{"L":null,"C":{"char_id":"MARIA_DELTA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L9_1","type":"dialog","speaker":"KYLE_DELTA_NULL_NULL","text":{"KOREA":"중장님께서 그렇게까지 말씀하신다면...... 알겠습니다.","JPN":"中将がそこまでおっしゃるなら……わかりました。","ENG":"If you say so, ma'am... Very well.","TWN":"既然中將都這麼說了……那我知道了。"},"stage":{"bg":"OFFICE","slots":{"L":null,"C":{"char_id":"KYLE_DELTA_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L12_1","type":"dialog","speaker":"SYLVIA_DELTA_NULL_NULL","text":{"KOREA":"그래서. 갑자기 생긴 여가시간을 어떻게 보내야 할지 몰라서 나한테 연락했다고?","JPN":"それで、急にもらっちゃった休暇をどう過ごせばいいかわからなくてアタシに連絡したわけ？","ENG":"So... You reached out to me because you couldn't figure out how to spend your free time?","TWN":"所以，你因為不知道如何度過這個突如其來的假期，所以才聯絡我？"},"stage":{"bg":"DORMITORY_2","slots":{"L":null,"C":{"char_id":"SYLVIA_DELTA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L13_1","type":"dialog","speaker":"KYLE_DELTA_NULL_NULL","text":{"KOREA":"저도 썩 내키진 않았습니다만.","JPN":"僕も気乗りしなかったんですが。","ENG":"Trust me, I wish I had a feasible alternative.","TWN":"雖然我也不是很樂意。"},"stage":{"bg":"DORMITORY_2","slots":{"L":null,"C":{"char_id":"KYLE_DELTA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L14_1","type":"dialog","speaker":"KYLE_DELTA_NULL_NULL","text":{"KOREA":"농땡이를 누구보다 잘 피우는 실비아 씨에게 연락하면 효율적인 조언을 받을 수 있을 것 같아서 말이죠.","JPN":"誰よりもサボり上手なシルビアさんに連絡すれば、効率的なアドバイスをもらえるんじゃないかと思いましたので。","ENG":"But I figured asking for your advice would be the most efficient course of action, having seen how talented you are at slacking off at work.","TWN":"但我想，希爾維亞小姐比任何人都會偷懶，似乎可以幫到我。"},"stage":{"bg":"DORMITORY_2","slots":{"L":null,"C":{"char_id":"KYLE_DELTA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L17_1","type":"dialog","speaker":"SYLVIA_DELTA_NULL_NULL","text":{"KOREA":"부정은 안 하겠지만 듣는 입장에서 기분이 영 이상하네.","JPN":"否定はしないけど、なんか気に障るわね。","ENG":"I guess I can't deny that, but it's not exactly flattering to hear that either.","TWN":"雖然我不否認這點，但聽到別人這麼說，感覺心情很複雜啊。"},"stage":{"bg":"DORMITORY_2","slots":{"L":{"char_id":"SYLVIA_DELTA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":null}}},{"id":"L18_1","type":"dialog","speaker":"SYLVIA_DELTA_NULL_NULL","text":{"KOREA":"좀 더 부탁하는 사람다운 태도로 말해볼래?","JPN":"もっと誠意を見せてほしいんだけど。","ENG":"Could you rephrase that as someone who needs my help?","TWN":"這就是你拜託別人的態度嗎？"},"stage":{"bg":"DORMITORY_2","slots":{"L":{"char_id":"SYLVIA_DELTA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":null}}},{"id":"L19_1","type":"dialog","speaker":"KYLE_DELTA_NULL_NULL","text":{"KOREA":"후, 좋습니다. 원하는 게 있으면 말씀하시죠.","JPN":"ふぅ、いいでしょう。何をお望みですか？","ENG":"*Sigh*... Very well. Please let me know if there's anything you'd like.","TWN":"唉，好吧，妳想要什麼，告訴我吧。"},"stage":{"bg":"DORMITORY_2","slots":{"L":{"char_id":"SYLVIA_DELTA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"KYLE_DELTA_NULL_NULL","face":"UNIT_DESPAIR"}}}},{"id":"L20_1","type":"dialog","speaker":"SYLVIA_DELTA_NULL_NULL","text":{"KOREA":"음~ 최근에 꽤 괜찮은 디저트 카페가 생겼다고 듣긴 했는데 말이지.","JPN":"う～ん実は、最近良さげなデザートが出てくる、いいカフェができたって聞いたんだけど。","ENG":"Hmm... I heard there's a new dessert cafe that's pretty decent.","TWN":"這個嘛～聽說這附近有一家不錯的甜點咖啡廳呢。"},"stage":{"bg":"DORMITORY_2","slots":{"L":{"char_id":"SYLVIA_DELTA_NULL_NULL","face":"UNIT_LAUGH"},"C":null,"R":{"char_id":"KYLE_DELTA_NULL_NULL","face":"UNIT_DESPAIR"}}}},{"id":"L23_1","type":"dialog","speaker":"YOONA_STREGA_NULL_NULL","text":{"KOREA":"오래 기다리셨습니다. 여왕폐하를 위한 달콤상큼 16종 디저트 세트 대령이오~","JPN":"お待たせしました。女王陛下のための甘くて爽やかなデザート16種セットをお持ちしました～。","ENG":"Thank you for your patience. Here comes the Sweet and Tart 16-piece Dessert Set for Her Majesty!","TWN":"讓您久等了，這是為女王殿下準備的16種甜點套餐～"},"stage":{"bg":"CAFE","slots":{"L":null,"C":{"char_id":"YOONA_STREGA_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L25_1","type":"dialog","speaker":"YOONA_STREGA_NULL_NULL","text":{"KOREA":"총-★ 총-★","JPN":"ぴょーん★ぴょーん★","ENG":"Ta-da!","TWN":"噠-★ 噠-★"},"stage":{"bg":"CAFE","slots":{"L":null,"C":null,"R":{"char_id":"YOONA_STREGA_NULL_NULL","face":"UNIT_LAUGH"}}}}]`);export{e as default};